def majority_vote(annotations: list[dict]) -> dict:
    """Aggregate labels using majority voting."""
    if not annotations:
        return {}

    labels = [a["label"] for a in annotations]
    counter = Counter(labels)
    most_common_label, vote_count = counter.most_common(1)[0]
    total_votes = len(labels)
    agreement_ratio = vote_count / total_votes

    return {
        "label": most_common_label,
        "vote_count": vote_count,
        "total_votes": total_votes,
        "agreement_ratio": agreement_ratio,
        "all_votes": dict(counter)
    }


def weighted_majority_vote(annotations: list[dict]) -> dict:
    """Aggregate labels using confidence-weighted majority voting."""
    if not annotations:
        return {}

    weighted_counts: dict = {}
    for a in annotations:
        label = a["label"]
        confidence = a.get("confidence", 1.0)
        weighted_counts[label] = weighted_counts.get(label, 0.0) + confidence

    most_common_label = max(weighted_counts, key=weighted_counts.get)
    total_weight = sum(weighted_counts.values())
    vote_count = sum(1 for a in annotations if a["label"] == most_common_label)
    total_votes = len(annotations)

    return {
        "label": most_common_label,
        "vote_count": vote_count,
        "total_votes": total_votes,
        "agreement_ratio": weighted_counts[most_common_label] / total_weight if total_weight > 0 else 0,
        "all_votes": {k: round(v, 3) for k, v in weighted_counts.items()}
    }


def update_aggregation(image_id: str):
    """Update the aggregated label for a given image."""
    if image_id in annotation_store and annotation_store[image_id]:
        result = majority_vote(annotation_store[image_id])
        aggregated_labels[image_id] = result


def update_annotator_stats(annotator_id: str, image_id: str):
    """Update annotator statistics."""
    if annotator_id not in annotator_stats:
        annotator_stats[annotator_id] = {
            "total_annotations": 0,
            "images_annotated": set()
        }
    annotator_stats[annotator_id]["total_annotations"] += 1
    annotator_stats[annotator_id]["images_annotated"].add(image_id)

