# --- Image Management ---

@app.post("/images/upload", response_model=dict)
async def upload_image(file: UploadFile = File(...)):
    """Upload an image for labeling."""
    if not file.content_type or not file.content_type.startswith("image/"):
        raise HTTPException(status_code=400, detail="File must be an image")

    image_id = str(uuid.uuid4())
    image_data = await file.read()

    image_store[image_id] = {
        "filename": file.filename,
        "data": image_data,
        "content_type": file.content_type
    }
    annotation_store[image_id] = []

    return {
        "image_id": image_id,
        "filename": file.filename,
        "message": "Image uploaded successfully"
    }


@app.post("/images/upload_batch", response_model=dict)
async def upload_images_batch(files: list[UploadFile] = File(...)):
    """Upload multiple images for labeling."""
    uploaded = []
