@app.get("/images", response_model=dict)
async def list_images(skip: int = 0, limit: int = 100, unlabeled_only: bool = False):
    """List all uploaded images with their annotation status."""
    images = []
    for image_id, info in image_store.items():
        num_annotations = len(annotation_store.get(image_id, []))
        agg = aggregated_labels.get(image_id)

        if unlabeled_only and num_annotations > 0:
            continue

        images.append({
            "image_id": image_id,
            "filename": info["filename"],
            "num_annotations": num_annotations,
            "aggregated_label": agg["label"] if agg else None,
            "agreement_ratio": agg["agreement_ratio"] if agg else None
        })

    total = len(images)
    images = images[skip:skip + limit]

    return {
        "total": total,
        "skip": skip,
        "limit": limit,
        "images": images
    }


