# --- Annotation Management ---

@app.post("/annotations", response_model=dict)
async def submit_annotation(annotation: AnnotationRequest):
    """Submit a label annotation for an image."""
    if annotation.image_id not in image_store:
        raise HTTPException(status_code=404, detail="Image not found")

    # Check if this annotator already labeled this image
    existing = annotation_store.get(annotation.image_id, [])
    for existing_ann in existing:
        if existing_ann["annotator_id"] == annotation.annotator_id:
            raise HTTPException(
                status_code=409,
                detail=f"Annotator {annotation.annotator_id} has already labeled image {annotation.image_id}"
            )

    ann_record = {
        "annotator_id": annotation.annotator_id,
        "label": annotation.label,
        "confidence": annotation.confidence
    }

    if annotation.image_id not in annotation_store:
        annotation_store[annotation.image_id] = []

    annotation_store[annotation.image_id].append(ann_record)
    label_classes.add(annotation.label)

    # Update aggregation
    update_aggregation(annotation.image_id)

    # Update annotator stats
    update_annotator_stats(annotation.annotator_id, annotation.image_id)

    return {
        "message": "Annotation submitted successfully",
        "image_id": annotation.image_id,
        "annotator_id": annotation.annotator_id,
        "label": annotation.label,
        "current_aggregation": aggregated_labels.get(annotation.image_id)
    }


@app.post("/annotations/batch", response_model=dict)
async def submit_batch_annotations(batch: BatchAnnotationRequest):
    """Submit multiple annotations at once."""
    results = []
    errors = []

    for annotation in batch.annotations:
        try:
            if annotation.image_id not in image_store:
                errors.append({
                    "image_id": annotation.image_id,
                    "error": "Image not found"
                })
                continue

            existing = annotation_store.get(annotation.image_id, [])
            already_labeled = any(
                a["annotator_id"] == annotation.annotator_id for a in existing
            )
            if already_labeled:
                errors.append({
                    "image_id": annotation.image_id,
                    "annotator_id": annotation.annotator_id,
                    "error": "Already labeled by this annotator"
                })
                continue

            ann_record = {
                "annotator_id": annotation.annotator_id,
                "label": annotation.label,
                "confidence": annotation.confidence
            }

            if annotation.image_id not in annotation_store:
                annotation_store[annotation.image_id] = []

            annotation_store[annotation.image_id].append(ann_record)
            label_classes.add(annotation.label)
            update_aggregation(annotation.image_id)
            update_annotator_stats(annotation.annotator_id, annotation.image_id)

            results.append({
                "image_id": annotation.image_id,
                "annotator_id": annotation.annotator_id,
                "label": annotation.label
            })
        except Exception as e:
            errors.append({
                "image_id": annotation.image_id,
                "error": str(e)
            })

    return {
        "successful": len(results),
        "failed": len(errors),
        "results": results,
        "errors": errors
    }


